const orcamento = $json.body || {};
const cliente = orcamento.cliente || {};
const dados_eletricos = orcamento.dados_eletricos || {};
const dados_conta = orcamento.dados_conta || {};
const calc = orcamento.dimensionamento_backup_calculado || {};
const cargas = orcamento.cargas_criticas || [];

const motivos_bloqueio = [];
const pendencias_criticas = [];
let status_killcritic = 'APROVADO';
let risco_killcritic = 'baixo';

// --- LEVEL 1: VALIDATION OF REQUIRED FIELDS & REGEX ---
if (!orcamento.protocolo || !/^ECO-[0-9]{8}-[0-9]{4}$/.test(orcamento.protocolo)) {
  motivos_bloqueio.push('Protocolo inválido ou fora do padrão (ECO-YYYYMMDD-XXXX).');
}

if (!cliente.nome || !cliente.tipo_cliente || !cliente.responsavel || !cliente.whatsapp || !cliente.email) {
  motivos_bloqueio.push('Dados cadastrais de cliente incompletos (nome, tipo, responsavel, whatsapp, email).');
}

if (!dados_eletricos.tensao || !dados_eletricos.tipo_ligacao || !dados_eletricos.disjuntor_geral || !dados_eletricos.padrao_entrada) {
  motivos_bloqueio.push('Dados elétricos básicos incompletos (tensao, tipo_ligacao, disjuntor_geral, padrao_entrada).');
}

if (!dados_conta.consumo_mensal_kwh || !dados_conta.valor_medio_conta || !dados_conta.concessionaria) {
  motivos_bloqueio.push('Dados da conta de energia incompletos (consumo, valor, concessionaria).');
}

// --- LEVEL 2: MATH & TECHNICAL LOGIC ---
if (calc.tem_motor_bloqueante) {
  status_killcritic = 'BLOQUEADO';
  risco_killcritic = 'alto';
  (calc.pendencias_cargas || []).forEach(p => motivos_bloqueio.push(p));
}

// Verificar se algum elevador ou motor pesado está nas cargas sem Avaliação Técnica
cargas.forEach(c => {
  const nome = c.nome_carga.toLowerCase();
  if (nome.includes('elevador') || nome.includes('incendio') || nome.includes('recalque') || nome.includes('ar condicionado central')) {
    status_killcritic = 'BLOQUEADO';
    risco_killcritic = 'alto';
    motivos_bloqueio.push(`Carga de alta potência/indução '${c.nome_carga}' incluída. Não é permitido dimensionamento de backup para essas cargas sem projeto específico.`);
  }

  if (cliente.tipo_cliente === 'restaurante') {
    if (nome.includes('fritadeira') || nome.includes('chapa') || nome.includes('forno') || nome.includes('resistencia')) {
      status_killcritic = 'BLOQUEADO';
      risco_killcritic = 'alto';
      motivos_bloqueio.push(`Carga térmica de cozinha comercial '${c.nome_carga}' incluída no backup preliminar (excluído por segurança).`);
    }
  }
});

if (calc.bateria_nominal_banco_kwh <= 0) {
  motivos_bloqueio.push('Capacidade nominal do banco de baterias calculado é zero.');
}

// --- LEVEL 3: TEXTUAL REVIEW & PROMISES BLOCKING ---
// (Estes serão analisados logicamente e por texto nos templates downstream)

// Se houver qualquer bloqueio, consolidar o status
if (motivos_bloqueio.length > 0) {
  status_killcritic = 'BLOQUEADO';
  risco_killcritic = 'alto';
  pendencias_criticas.push('Necessário agendar Avaliação Técnica presencial para sanar bloqueios de engenharia.');
} else {
  // Se passou sem bloqueios severos, mas necessita de validação física
  status_killcritic = 'APROVADO_COM_RESSALVAS';
  risco_killcritic = 'medio';
  pendencias_criticas.push('Confirmar local físico de instalação e ventilação adequada do inversor e baterias.');
  pendencias_criticas.push('Validar custos reais de importação de equipamentos com a Corsolar.');
}

const status_orcamento = (status_killcritic === 'BLOQUEADO') ? 'bloqueado_killcritic' : 'aprovado_para_proposta';

return {
  ...orcamento,
  compliance_killcritic: {
    status_killcritic,
    risco_killcritic,
    motivos_bloqueio,
    pendencias_criticas,
    revisao_textual_aprovada: true,
    valida_calculo_aprovada: status_killcritic !== 'BLOQUEADO'
  },
  status: status_orcamento
};
